cd /workspace/repo && sed -i '315,326s/.*/    def get_signing_serializer(self, app: Flask) -> URLSafeTimedSerializer | None:
        if not app.secret_key:
            return None
        signer_kwargs = dict(
            key_derivation=app.config.get(
                "SESSION_KEY_DERIVATION", self.key_derivation
            ),
            digest_method=app.config.get("SESSION_DIGEST_METHOD", self.digest_method),
        )
        return URLSafeTimedSerializer(
            app.secret_key,
            salt=self.salt,
            serializer=self.serializer,
            signer_kwargs=signer_kwargs,
        )/' src/flask/sessions.py

cat > /tmp/new_get_signing_serializer.py << 'EOF'
    def get_signing_serializer(self, app: Flask) -> URLSafeTimedSerializer | None:
        if not app.secret_key:
            return None
        signer_kwargs = dict(
            key_derivation=self.key_derivation, digest_method=self.digest_method
        )
        keys = [app.secret_key] + list(app.config["SECRET_KEY_FALLBACKS"])
        return URLSafeTimedSerializer(
            keys,
            salt=self.salt,
            serializer=self.serializer,
            signer_kwargs=signer_kwargs,
        )
EOF
cat /tmp/new_get_signing_serializer.py
